const WebSocket = require('ws');
const http = require('http');

const server = http.createServer();
const wss = new WebSocket.Server({ server });

// Game state
const gameState = {
  players: new Map(),
  units: new Map(),
  buildings: new Map(),
  nextUnitId: 1,
  nextBuildingId: 1,
  mapWidth: 1000,
  mapHeight: 1000,
};

// Unit types with stats
const UNIT_TYPES = {
  warrior: { hp: 100, attack: 15, defense: 5, speed: 3, range: 1, cost: { gold: 50 } },
  archer: { hp: 60, attack: 20, defense: 2, speed: 2, range: 8, cost: { gold: 70 } },
  cavalry: { hp: 120, attack: 18, defense: 8, speed: 6, range: 1, cost: { gold: 100 } },
  siege: { hp: 200, attack: 40, defense: 3, speed: 1, range: 10, cost: { gold: 200 } },
};

// Building types with stats
const BUILDING_TYPES = {
  base: { hp: 500, cost: { gold: 0 }, buildTime: 0, producesUnits: ['warrior', 'archer'] },
  barracks: { hp: 300, cost: { gold: 150 }, buildTime: 5000, producesUnits: ['warrior', 'cavalry'] },
  archery_range: { hp: 250, cost: { gold: 120 }, buildTime: 4000, producesUnits: ['archer'] },
  workshop: { hp: 400, cost: { gold: 250 }, buildTime: 8000, producesUnits: ['siege'] },
  tower: { hp: 200, cost: { gold: 100 }, buildTime: 3000, producesUnits: [], attack: 25, range: 12 },
  mine: { hp: 150, cost: { gold: 80 }, buildTime: 4000, producesUnits: [], goldPerTick: 5 },
};

class Player {
  constructor(id, ws) {
    this.id = id;
    this.ws = ws;
    this.name = `Player_${id}`;
    this.resources = { gold: 500 };
    this.color = this.generateColor();
    this.alive = true;
    this.spawnX = 0;
    this.spawnY = 0;
  }

  generateColor() {
    const colors = ['#FF4444', '#4444FF', '#44FF44', '#FFFF44', '#FF44FF', '#44FFFF', '#FF8800', '#8800FF'];
    return colors[this.id % colors.length];
  }

  send(type, data) {
    if (this.ws.readyState === WebSocket.OPEN) {
      this.ws.send(JSON.stringify({ type, ...data }));
    }
  }
}

class Unit {
  constructor(id, playerId, type, x, y) {
    const stats = UNIT_TYPES[type];
    this.id = id;
    this.playerId = playerId;
    this.type = type;
    this.x = x;
    this.y = y;
    this.hp = stats.hp;
    this.maxHp = stats.hp;
    this.attack = stats.attack;
    this.defense = stats.defense;
    this.speed = stats.speed;
    this.range = stats.range;
    this.targetX = null;
    this.targetY = null;
    this.attackTargetId = null;
    this.state = 'idle'; // idle, moving, attacking
  }

  toJSON() {
    return {
      id: this.id,
      playerId: this.playerId,
      type: this.type,
      x: this.x,
      y: this.y,
      hp: this.hp,
      maxHp: this.maxHp,
      state: this.state,
      attackTargetId: this.attackTargetId,
    };
  }
}

class Building {
  constructor(id, playerId, type, x, y) {
    const stats = BUILDING_TYPES[type];
    this.id = id;
    this.playerId = playerId;
    this.type = type;
    this.x = x;
    this.y = y;
    this.hp = stats.hp;
    this.maxHp = stats.hp;
    this.buildProgress = type === 'base' ? 1 : 0;
    this.buildTime = stats.buildTime;
    this.completed = type === 'base';
    this.productionQueue = [];
    this.attack = stats.attack || 0;
    this.range = stats.range || 0;
    this.goldPerTick = stats.goldPerTick || 0;
  }

  toJSON() {
    return {
      id: this.id,
      playerId: this.playerId,
      type: this.type,
      x: this.x,
      y: this.y,
      hp: this.hp,
      maxHp: this.maxHp,
      completed: this.completed,
      buildProgress: this.buildProgress,
      productionQueue: this.productionQueue,
    };
  }
}

// Helper functions
function distance(x1, y1, x2, y2) {
  return Math.sqrt((x2 - x1) ** 2 + (y2 - y1) ** 2);
}

function clamp(val, min, max) {
  return Math.max(min, Math.min(max, val));
}

function generateSpawnPosition(playerIndex) {
  const positions = [
    { x: 100, y: 100 },
    { x: 900, y: 900 },
    { x: 100, y: 900 },
    { x: 900, y: 100 },
    { x: 500, y: 100 },
    { x: 500, y: 900 },
    { x: 100, y: 500 },
    { x: 900, y: 500 },
  ];
  return positions[playerIndex % positions.length];
}

function broadcastToAll(type, data) {
  for (const [, player] of gameState.players) {
    player.send(type, data);
  }
}

function broadcastGameState() {
  const units = Array.from(gameState.units.values()).map(u => u.toJSON());
  const buildings = Array.from(gameState.buildings.values()).map(b => b.toJSON());
  const players = Array.from(gameState.players.values()).map(p => ({
    id: p.id,
    name: p.name,
    resources: p.resources,
    color: p.color,
    alive: p.alive,
  }));

  broadcastToAll('game_state', { units, buildings, players });
}

function spawnPlayerBase(player) {
  const spawn = generateSpawnPosition(player.id);
  player.spawnX = spawn.x;
  player.spawnY = spawn.y;

  // Create base building
  const baseId = gameState.nextBuildingId++;
  const base = new Building(baseId, player.id, 'base', spawn.x, spawn.y);
  gameState.buildings.set(baseId, base);

  // Create starting units
  for (let i = 0; i < 3; i++) {
    const unitId = gameState.nextUnitId++;
    const unit = new Unit(unitId, player.id, 'warrior', spawn.x + 20 + i * 15, spawn.y + 30);
    gameState.units.set(unitId, unit);
  }

  console.log(`Spawned base and starting units for ${player.name} at (${spawn.x}, ${spawn.y})`);
}

// Command handlers
function handleBuild(player, data) {
  const { buildingType, x, y } = data;

  if (!BUILDING_TYPES[buildingType]) {
    player.send('error', { message: `Unknown building type: ${buildingType}` });
    return;
  }

  if (buildingType === 'base') {
    player.send('error', { message: 'Cannot build additional bases' });
    return;
  }

  const typeDef = BUILDING_TYPES[buildingType];
  const cost = typeDef.cost;

  // Check resources
  for (const [resource, amount] of Object.entries(cost)) {
    if ((player.resources[resource] || 0) < amount) {
      player.send('error', { message: `Not enough ${resource}. Need ${amount}, have ${player.resources[resource] || 0}` });
      return;
    }
  }

  // Check position bounds
  const bx = clamp(x, 0, gameState.mapWidth);
  const by = clamp(y, 0, gameState.mapHeight);

  // Check for overlapping buildings (minimum distance of 30)
  for (const [, building] of gameState.buildings) {
    if (distance(bx, by, building.x, building.y) < 30) {
      player.send('error', { message: 'Too close to another building' });
      return;
    }
  }

  // Deduct resources
  for (const [resource, amount] of Object.entries(cost)) {
    player.resources[resource] -= amount;
  }

  const buildingId = gameState.nextBuildingId++;
  const building = new Building(buildingId, player.id, buildingType, bx, by);
  gameState.buildings.set(buildingId, building);

  console.log(`${player.name} started building ${buildingType} at (${bx}, ${by})`);

  broadcastToAll('building_started', {
    building: building.toJSON(),
    playerId: player.id,
  });

  player.send('resources_updated', { resources: player.resources });
}

function handleTrainUnit(player, data) {
  const { buildingId, unitType } = data;

  const building = gameState.buildings.get(buildingId);
  if (!building) {
    player.send('error', { message: 'Building not found' });
    return;
  }

  if (building.playerId !== player.id) {
    player.send('error', { message: 'Not your building' });
    return;
  }

  if (!building.completed) {
    player.send('error', { message: 'Building not yet completed' });
    return;
  }

  const buildingDef = BUILDING_TYPES[building.type];
  if (!buildingDef.producesUnits.includes(unitType)) {
    player.send('error', { message: `This building cannot produce ${unitType}` });
    return;
  }

  if (!UNIT_TYPES[unitType]) {
    player.send('error', { message: `Unknown unit type: ${unitType}` });
    return;
  }

  const unitDef = UNIT_TYPES[unitType];
  const cost = unitDef.cost;

  // Check resources
  for (const [resource, amount] of Object.entries(cost)) {
    if ((player.resources[resource] || 0) < amount) {
      player.send('error', { message: `Not enough ${resource}. Need ${amount}, have ${player.resources[resource] || 0}` });
      return;
    }
  }

  // Deduct resources
  for (const [resource, amount] of Object.entries(cost)) {
    player.resources[resource] -= amount;
  }

  // Add to production queue
  building.productionQueue.push({
    unitType,
    progress: 0,
    trainTime: 3000, // 3 seconds to train
  });

  console.log(`${player.name} queued ${unitType} at building ${buildingId}`);

  player.send('resources_updated', { resources: player.resources });
  broadcastToAll('unit_queued', {
    buildingId,
    unitType,
    playerId: player.id,
    queueLength: building.productionQueue.length,
  });
}

function handleMove(player, data) {
  const { unitIds, targetX, targetY } = data;

  if (!Array.isArray(unitIds) || unitIds.length === 0) {
    player.send('error', { message: 'No units specified' });
    return;
  }

  const tx = clamp(targetX, 0, gameState.mapWidth);
  const ty = clamp(targetY, 0, gameState.mapHeight);

  const movedUnits = [];

  for (const unitId of unitIds) {
    const unit = gameState.units.get(unitId);
    if (!unit) continue;
    if (unit.playerId !== player.id) continue;

    unit.targetX = tx;
    unit.targetY = ty;
    unit.attackTargetId = null;
    unit.state = 'moving';
    movedUnits.push(unitId);
  }

  if (movedUnits.length > 0) {
    broadcastToAll('units_moving', {
      unitIds: movedUnits,
      targetX: tx,
      targetY: ty,
      playerId: player.id,
    });
  }
}

function handleAttack(player, data) {
  const { unitIds, targetId, targetType } = data;

  if (!Array.isArray(unitIds) || unitIds.length === 0) {
    player.send('error', { message: 'No units specified' });
    return;
  }

  // Validate target exists
  let target;
  if (targetType === 'unit') {
    target = gameState.units.get(targetId);
  } else if (targetType === 'building') {
    target = gameState.buildings.get(targetId);
  }

  if (!target) {
    player.send('error', { message: 'Target not found' });
    return;
  }

  if (target.playerId === player.id) {
    player.send('error', { message: 'Cannot attack your own units/buildings' });
    return;
  }

  const attackingUnits = [];

  for (const unitId of unitIds) {
    const unit = gameState.units.get(unitId);
    if (!unit) continue;
    if (unit.playerId !== player.id) continue;

    unit.attackTargetId = targetId;
    unit.attackTargetType = targetType;
    unit.state = 'attacking';
    unit.targetX = target.x;
    unit.targetY = target.y;
    attackingUnits.push(unitId);
  }

  if (attackingUnits.length > 0) {
    broadcastToAll('units_attacking', {
      unitIds: attackingUnits,
      targetId,
      targetType,
      playerId: player.id,
    });
  }
}

function handleStop(player, data) {
  const { unitIds } = data;

  if (!Array.isArray(unitIds)) return;

  for (const unitId of unitIds) {
    const unit = gameState.units.get(unitId);
    if (!unit || unit.playerId !== player.id) continue;

    unit.state = 'idle';
    unit.targetX = null;
    unit.targetY = null;
    unit.attackTargetId = null;
  }

  broadcastToAll('units_stopped', { unitIds, playerId: player.id });
}

function handleChat(player, data) {
  const { message } = data;
  if (!message || typeof message !== 'string') return;

  const sanitized = message.substring(0, 200);

  broadcastToAll('chat', {
    playerId: player.id,
    playerName: player.name,
    message: sanitized,
  });
}

